async (page) => {
  // The map shows a corridor at x=200 going north - click near y=136
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 200, y: 136});
  await page.waitForTimeout(3000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify(pos);
}

async (page) => {
  // Click nearest Oak tree to chop it
  const result = await page.evaluate((label) => JSON.stringify(window.__clickEntity(label)), 'E1');
  await page.waitForTimeout(4000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const gs = JSON.parse(state);
  return JSON.stringify({
    pos: gs.player_position,
    inventory: gs.inventory,
    skills: gs.skills,
    recent_chat: gs.ui_state.recent_chat
  });
}

async (page) => {
  // Click the Oak tree directly on canvas to trigger chopping
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 600, y: 384 });
  await page.waitForTimeout(5000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const gs = JSON.parse(state);
  return JSON.stringify({
    pos: gs.player_position,
    inventory: gs.inventory,
    skills: gs.skills,
    recent_chat: gs.ui_state.recent_chat
  });
}
